CREATE TABLE IF NOT EXISTS lemana_categories (
  id VARCHAR(255) PRIMARY KEY,
  name VARCHAR(255) NOT NULL,
  url VARCHAR(255)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


CREATE TABLE IF NOT EXISTS lemana_products (
  id VARCHAR(255) PRIMARY KEY,
  category_id VARCHAR(255),
  name VARCHAR(255) NOT NULL,
  price DECIMAL(10, 2),
  raw_price VARCHAR(255),
  url VARCHAR(255),
  FOREIGN KEY (category_id) REFERENCES lemana_categories(id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


